solutions.python:
import sys

class Solution:
    def solve(self) -> None:
        t = int(input())
        results = ''
        for _ in range(t):
            n = int(input())
            result = self.count_trailing_zeros(n)
            results += str(result) + '\n'
        sys.stdout.write(results)

    def count_trailing_zeros(self, n: int) -> int:
        cnt = 0
        while n % 2 == 0:
            cnt += 1
            n //= 2
        return cnt

if __name__ == '__main__':
    solution = Solution()
    solution.solve()

